SELECT r.*, ste.site_nm AS site_nm, vnd.vendor_nm AS vendor_nm, raw.prod_nm AS settle_raw_nm, cd_rt.code_label AS recon_type_cd_nm, cd_rs.code_label AS recon_status_cd_nm FROM st_recon r LEFT JOIN sy_site ste ON ste.site_id = r.site_id LEFT JOIN sy_vendor vnd ON vnd.vendor_id = r.vendor_id LEFT JOIN st_settle_raw raw ON raw.settle_raw_id = r.settle_raw_id LEFT JOIN sy_code cd_rt ON cd_rt.code_grp = 'RECON_TYPE' AND cd_rt.code_value = r.recon_type_cd LEFT JOIN sy_code cd_rs ON cd_rs.code_grp = 'RECON_STATUS' AND cd_rs.code_value = r.recon_status_cd
ORDER BY r.recon_id ASC ORDER BY r.recon_id DESC ORDER BY r.reg_date ASC ORDER BY r.reg_date DESC ORDER BY r.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

