UPDATE st_recon
site_id = #{siteId}, vendor_id = #{vendorId}, recon_type_cd = #{reconTypeCd}, recon_status_cd = #{reconStatusCd}, recon_status_cd_before = #{reconStatusCdBefore}, settle_id = #{settleId}, settle_raw_id = #{settleRawId}, ref_id = #{refId}, ref_no = #{refNo}, settle_period = #{settlePeriod}, expected_amt = #{expectedAmt}, actual_amt = #{actualAmt}, diff_amt = #{diffAmt}, recon_note = #{reconNote}, resolved_by = #{resolvedBy}, resolved_date = #{resolvedDate}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE recon_id = #{reconId}
